CREATE OR REPLACE FUNCTION fpb_get_grade_at_date ( as_memno text , adt_balance_date timestamp(0) ) RETURNS varchar AS $body$
DECLARE

ls_other_code  sc_rep_mem_share_loan_bal.other_code%type;

BEGIN
--Mook 2021-03-22 Amnat
select  other_code into STRICT ls_other_code
from sc_rep_mem_share_loan_bal
where 1=1
and membership_no = as_memno
and balance_date = adt_balance_date
and other_code != ' '
;

  RETURN ls_other_code;

  
END;
$body$
